// Global variables for filter states
let currentProject = "";
let currentVersion = "";
let currentStage = "";
let activeTab = "scurve-tab";
let chartInstance = null;

// Initialize selectors
const projectSelect = document.getElementById("projectSelect");
const versionSelect = document.getElementById("versionSelect");
const stageSelect = document.getElementById("stageSelect");

// Format dates beautifully
function formatDate(dStr) {
    if (!dStr) return "—";
    const date = new Date(dStr + "T00:00:00");
    if (isNaN(date.getTime())) return dStr;
    return date.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
}

// Initialize theme switcher icons
const initTheme = localStorage.getItem("theme") || "dark";
document.getElementById("theme-toggle-icon").className = initTheme === "dark" ? "fa-solid fa-sun text-sm" : "fa-solid fa-moon text-sm";

function toggleTheme() {
    const isDark = document.documentElement.classList.contains("dark");
    const newTheme = isDark ? "light" : "dark";

    if (newTheme === "dark") {
        document.documentElement.classList.add("dark");
        document.getElementById("theme-toggle-icon").className = "fa-solid fa-sun text-sm";
    } else {
        document.documentElement.classList.remove("dark");
        document.getElementById("theme-toggle-icon").className = "fa-solid fa-moon text-sm";
    }
    localStorage.setItem("theme", newTheme);
    updateCharts();
}

// Initialize dropdowns from injected data
function initSelectors() {
    projectSelect.innerHTML = "";
    const projects = Object.keys(PROJECT_DATA).sort();
    projects.forEach(p => {
        const opt = document.createElement("option");
        opt.value = p;
        opt.textContent = p;
        projectSelect.appendChild(opt);
    });

    // Default project
    currentProject = projects.includes("D3MC Centinela - Skyline") ? "D3MC Centinela - Skyline" : projects[0];
    projectSelect.value = currentProject;

    loadVersions(currentProject);
}

function loadVersions(proj) {
    versionSelect.innerHTML = "";
    const versions = Object.keys(PROJECT_DATA[proj]).sort();
    versions.forEach(v => {
        const opt = document.createElement("option");
        opt.value = v;
        opt.textContent = v ? v : "Default";
        versionSelect.appendChild(opt);
    });

    // Default version
    currentVersion = versions.includes("Rev 4") ? "Rev 4" : versions[0];
    versionSelect.value = currentVersion;

    loadStages(proj, currentVersion);
}

function loadStages(proj, ver) {
    stageSelect.innerHTML = '<option value="">All Stages</option>';
    const subsystems = PROJECT_DATA[proj][ver].subsystems;
    const stages = [...new Set(subsystems.map(s => s.etapa).filter(Boolean))].sort();
    stages.forEach(st => {
        const opt = document.createElement("option");
        opt.value = st;
        opt.textContent = st;
        stageSelect.appendChild(opt);
    });

    currentStage = "";
    stageSelect.value = "";

    loadMilestoneTypes(proj, ver);
    renderFilters();
    updateDashboard();
}

function loadMilestoneTypes(proj, ver) {
    const milestoneSelect = document.getElementById("milestoneTypeSelect");
    if (!milestoneSelect) return;
    milestoneSelect.innerHTML = "";

    const subsystems = PROJECT_DATA[proj][ver].subsystems;
    const mTypes = new Set();
    subsystems.forEach(s => {
        if (s.milestones) {
            Object.keys(s.milestones).forEach(k => mTypes.add(k));
        }
    });

    const ORDERED_TYPES = ["Walkdown 1", "Walkdown 2", "CRP", "Walkdown 3", "Walkdown 4", "TOP"];
    const availableTypes = Array.from(mTypes).sort((a, b) => {
        const idxA = ORDERED_TYPES.indexOf(a);
        const idxB = ORDERED_TYPES.indexOf(b);
        if (idxA === -1) return 1;
        if (idxB === -1) return -1;
        return idxA - idxB;
    });

    availableTypes.forEach(t => {
        const opt = document.createElement("option");
        opt.value = t;
        opt.textContent = t;
        milestoneSelect.appendChild(opt);
    });
}

// Get flag filters that contain at least one true value in the active dataset
function getActiveFlagFilters() {
    if (!currentProject || !currentVersion) return [];
    const subsystems = PROJECT_DATA[currentProject][currentVersion].subsystems;
    const flagsList = [
        { key: "energizacion_definitiva", label: "Definitive Energization" },
        { key: "domos", label: "Domes" },
        { key: "espesadores", label: "Thickeners" },
        { key: "llenado_piscinas", label: "Pool Filling" },
        { key: "water_run_1", label: "Water Run 1" },
        { key: "water_run_2", label: "Water Run 2" }
    ];
    return flagsList.filter(f => subsystems.some(s => s.flags && s.flags[f.key]));
}

function renderFilters() {
    const container = document.getElementById("dynamic-filters-container");
    if (!container) return;
    container.innerHTML = '<span class="text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">Milestone Filters:</span>';

    const activeFilters = getActiveFlagFilters();
    if (activeFilters.length === 0) {
        document.getElementById("filter-bar-container").classList.add("hidden");
        return;
    }

    document.getElementById("filter-bar-container").classList.remove("hidden");
    activeFilters.forEach(f => {
        container.innerHTML += `
            <label class="inline-flex items-center space-x-1.5 bg-slate-100 dark:bg-slate-800/80 px-2.5 py-1 rounded-lg text-xs cursor-pointer border border-slate-200 dark:border-white/5 hover:border-brand-500 transition-colors">
                <input type="checkbox" id="flag-${f.key}" onchange="applyFilters()" class="text-brand-500 focus:ring-brand-500 rounded">
                <span>${f.label}</span>
            </label>
        `;
    });
}

function onProjectChange(val) {
    currentProject = val;
    loadVersions(currentProject);
}

function onVersionChange(val) {
    currentVersion = val;
    loadStages(currentProject, currentVersion);
}

function onStageChange(val) {
    currentStage = val;
    updateDashboard();
}

// Apply filters (milestone flags)
function getFilteredSubsystems() {
    if (!currentProject || !currentVersion) return [];

    const subsystems = PROJECT_DATA[currentProject][currentVersion].subsystems;
    let filtered = subsystems;

    if (currentStage) {
        filtered = filtered.filter(sub => sub.etapa === currentStage);
    }

    const activeFilters = getActiveFlagFilters();
    activeFilters.forEach(f => {
        const chk = document.getElementById(`flag-${f.key}`);
        if (chk && chk.checked) {
            filtered = filtered.filter(sub => sub.flags && sub.flags[f.key]);
        }
    });

    return filtered;
}

function resetFilters() {
    const activeFilters = getActiveFlagFilters();
    activeFilters.forEach(f => {
        const chk = document.getElementById(`flag-${f.key}`);
        if (chk) chk.checked = false;
    });
    applyFilters();
}

function applyFilters() {
    updateDashboard();
}

// Tab switcher
function switchTab(tabId) {
    activeTab = tabId;
    document.querySelectorAll(".tab-btn").forEach(btn => {
        btn.classList.remove("active-tab", "text-brand-500", "dark:text-brand-500");
        btn.classList.add("text-slate-500", "dark:text-slate-400");
    });
    document.querySelectorAll(".tab-content").forEach(c => c.classList.add("hidden"));

    document.getElementById(`${tabId}-btn`).classList.add("active-tab");
    document.getElementById(`${tabId}-content`).classList.remove("hidden");

    updateTabSpecifics();
}

function updateTabSpecifics() {
    if (activeTab === "scurve-tab") {
        updateCharts();
    } else if (activeTab === "skyline-tab") {
        updateSkyline();
    }
}

// Recalculate KPIs based on filtered data
