// Render Skyline Schedule Timeline view
function updateSkyline() {
    if (activeTab !== "skyline-tab") return;

    const skylineGrid = document.getElementById("skyline-grid");
    if (!skylineGrid) return;
    skylineGrid.innerHTML = "";

    const filteredSubs = getFilteredSubsystems();
    const milestoneSelect = document.getElementById("milestoneTypeSelect");
    const mType = milestoneSelect ? milestoneSelect.value : "";

    if (!mType) {
        skylineGrid.innerHTML = '<div class="text-slate-500 text-xs py-10 w-full text-center">No milestone type selected.</div>';
        return;
    }

    // Group subsystems by the scheduled week of the selected milestone type
    const subsWithMilestone = filteredSubs.filter(s => s.milestones && s.milestones[mType] && s.milestones[mType].week);

    if (subsWithMilestone.length === 0) {
        skylineGrid.innerHTML = '<div class="text-slate-500 text-xs py-10 w-full text-center">No subsystems found for this milestone and filters.</div>';
        return;
    }

    // Group by week
    const groupsByWeek = {};
    subsWithMilestone.forEach(s => {
        const wk = s.milestones[mType].week;
        if (!groupsByWeek[wk]) {
            groupsByWeek[wk] = [];
        }
        groupsByWeek[wk].push(s);
    });

    // Sort weeks chronologically
    const sortedWeeks = Object.keys(groupsByWeek).sort();

    // Render columns
    sortedWeeks.forEach(wk => {
        const colDiv = document.createElement("div");
        colDiv.className = "flex flex-col items-center space-y-2 min-w-[150px] max-w-[170px]";

        // Format week date header
        const weekDate = new Date(wk + "T00:00:00");
        const formattedWeek = weekDate.toLocaleDateString("en-GB", { day: "2-digit", month: "short" });

        const colHeader = document.createElement("div");
        colHeader.className = "text-center pb-2 border-b border-slate-200 dark:border-white/5 w-full";
        colHeader.innerHTML = `
            <div class="font-outfit font-bold text-slate-800 dark:text-slate-200 text-xs">${formattedWeek}</div>
            <div class="text-[9px] text-slate-400 dark:text-slate-500">${wk}</div>
        `;
        colDiv.appendChild(colHeader);

        // Sort subsystems by the index value
        const subsInWeek = groupsByWeek[wk].sort((a, b) => {
            const idxA = a.milestones[mType].index || 0;
            const idxB = b.milestones[mType].index || 0;
            return idxA - idxB;
        });

        // Stack cards bottom-up using flex-col-reverse
        const stackContainer = document.createElement("div");
        stackContainer.className = "flex flex-col-reverse w-full space-y-1.5 space-y-reverse overflow-y-auto";

        subsInWeek.forEach(sub => {
            const card = document.createElement("div");
            card.className = "glass-panel px-2.5 py-2 rounded-lg border border-slate-200 dark:border-white/10 hover:border-brand-500 hover:scale-[1.03] transition-all cursor-pointer shadow-sm text-center select-none active:scale-[0.98]";
            card.onclick = () => openDrawer(sub);
            card.title = `${sub.code} - ${sub.description}`;

            card.innerHTML = `
                <div class="font-outfit font-semibold text-slate-900 dark:text-slate-100 text-[11px] truncate">${sub.code}</div>
                <div class="text-[9px] text-slate-500 dark:text-slate-400 truncate max-w-full">${sub.description}</div>
            `;
            stackContainer.appendChild(card);
        });

        colDiv.appendChild(stackContainer);
        skylineGrid.appendChild(colDiv);
    });
}

