args.TargetContent:
// Global variables for filter states
let currentProject = "";
let currentVersion = "";
let currentStage = "";
let activeTab = "scurve-tab";
let chartInstance = null;

// Initialize selectors
const projectSelect = document.getElementById("projectSelect");
const versionSelect = document.getElementById("versionSelect");
const stageSelect = document.getElementById("stageSelect");

// Format dates beautifully
function formatDate(dStr) {
    if (!dStr) return "—";
    const date = new Date(dStr + "T00:00:00");
    if (isNaN(date.getTime())) return dStr;
    return date.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
}

// Initialize theme switcher icons
const initTheme = localStorage.getItem("theme") || "dark";
document.getElementById("theme-toggle-icon").className = initTheme === "dark" ? "fa-solid fa-sun text-sm" : "fa-solid fa-moon text-sm";

function toggleTheme() {
    const isDark = document.documentElement.classList.contains("dark");
    const newTheme = isDark ? "light" : "dark";

    if (newTheme === "dark") {
        document.documentElement.classList.add("dark");
        document.getElementById("theme-toggle-icon").className = "fa-solid fa-sun text-sm";
    } else {
        document.documentElement.classList.remove("dark");
        document.getElementById("theme-toggle-icon").className = "fa-solid fa-moon text-sm";
    }
    localStorage.setItem("theme", newTheme);
    updateCharts();
}

// Initialize dropdowns from injected data
function initSelectors() {
    projectSelect.innerHTML = "";
    const projects = Object.keys(PROJECT_DATA).sort();
    projects.forEach(p => {
        const opt = document.createElement("option");
        opt.value = p;
        opt.textContent = p;
        projectSelect.appendChild(opt);
    });

    // Default project
    currentProject = projects.includes("D3MC Centinela - Skyline") ? "D3MC Centinela - Skyline" : projects[0];
    projectSelect.value = currentProject;

    loadVersions(currentProject);
}

function loadVersions(proj) {
    versionSelect.innerHTML = "";
    const versions = Object.keys(PROJECT_DATA[proj]).sort();
    versions.forEach(v => {
        const opt = document.createElement("option");
        opt.value = v;
        opt.textContent = v ? v : "Default";
        versionSelect.appendChild(opt);
    });

    // Default version
    currentVersion = versions.includes("Rev 4") ? "Rev 4" : versions[0];
    versionSelect.value = currentVersion;

    loadStages(proj, currentVersion);
}

function loadStages(proj, ver) {
    stageSelect.innerHTML = '<option value="">All Stages</option>';
    const subsystems = PROJECT_DATA[proj][ver].subsystems;
    const stages = [...new Set(subsystems.map(s => s.etapa).filter(Boolean))].sort();
    stages.forEach(st => {
        const opt = document.createElement("option");
        opt.value = st;
        opt.textContent = st;
        stageSelect.appendChild(opt);
    });

    currentStage = "";
    stageSelect.value = "";

    updateDashboard();
}

function onProjectChange(val) {
    currentProject = val;
    loadVersions(currentProject);
}

function onVersionChange(val) {
    currentVersion = val;
    loadStages(currentProject, currentVersion);
}

function onStageChange(val) {
    currentStage = val;
    updateDashboard();
}

// Apply filters (milestone flags and search queries)
function getFilteredSubsystems() {
    if (!currentProject || !currentVersion) return [];

    const subsystems = PROJECT_DATA[currentProject][currentVersion].subsystems;
    const search = document.getElementById("search-input").value.toLowerCase().trim();
    const flagEnergizacion = document.getElementById("flag-energizacion").checked;
    const flagDomos = document.getElementById("flag-domos").checked;
    const flagEspesadores = document.getElementById("flag-espesadores").checked;
    const flagPiscinas = document.getElementById("flag-piscinas").checked;
    const flagWaterrun1 = document.getElementById("flag-waterrun1").checked;
    const flagWaterrun2 = document.getElementById("flag-waterrun2").checked;

    return subsystems.filter(sub => {
        // Filter by stage
        if (currentStage && sub.etapa !== currentStage) return false;

        // Filter by search query
        if (search && !sub.code.toLowerCase().includes(search) && !sub.description.toLowerCase().includes(search)) {
            return false;
        }

        // Filter by custom flags
        if (flagEnergizacion && !sub.flags.energizacion_definitiva) return false;
        if (flagDomos && !sub.flags.domos) return false;
        if (flagEspesadores && !sub.flags.espesadores) return false;
        if (flagPiscinas && !sub.flags.llenado_piscinas) return false;
        if (flagWaterrun1 && !sub.flags.water_run_1) return false;
        if (flagWaterrun2 && !sub.flags.water_run_2) return false;

        return true;
    });
}

function resetFilters() {
    document.getElementById("flag-energizacion").checked = false;
    document.getElementById("flag-domos").checked = false;
    document.getElementById("flag-espesadores").checked = false;
    document.getElementById("flag-piscinas").checked = false;
    document.getElementById("flag-waterrun1").checked = false;
    document.getElementById("flag-waterrun2").checked = false;
    document.getElementById("search-input").value = "";
    applyFilters();
}

function applyFilters() {
    updateDashboard();
}

// Tab switcher
function switchTab(tabId) {
    activeTab = tabId;
    document.querySelectorAll(".tab-btn").forEach(btn => {
        btn.classList.remove("active-tab", "text-brand-500", "dark:text-brand-500");
        btn.classList.add("text-slate-500", "dark:text-slate-400");
    });
    document.querySelectorAll(".tab-content").forEach(c => c.classList.add("hidden"));

    document.getElementById(`${tabId}-btn`).classList.add("active-tab");
    document.getElementById(`${tabId}-content`).classList.remove("hidden");

    updateTabSpecifics();
}

function updateTabSpecifics() {
    if (activeTab === "scurve-tab") {
        updateCharts();
    } else if (activeTab === "matrix-tab") {
        renderMatrix();
    } else if (activeTab === "list-tab") {
        renderSubsystemsTable();
    }
}

// Recalculate KPIs based on filtered data
function updateKPIs(filteredSubs) {
    const container = document.getElementById("kpi-container");
    container.innerHTML = "";

    const total = filteredSubs.length;
    const completedTOP = filteredSubs.filter(s => s.dates['TOP']).length;
