                    </div>
                    <div>
                        <span class="text-[10px] uppercase font-bold text-slate-500 block">Energización Definitiva</span>
                        <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Ener. Gen.'])}</span>
                    </div>
                    <div>
                        <span class="text-[10px] uppercase font-bold text-slate-500 block">Caminata 4</span>
