                <div class="bg-brand-500/10 text-brand-500 border border-brand-500/25 px-4 py-2.5 rounded-2xl text-center font-bold font-outfit text-base">
                    ${formatDate(sub.dates['TOP'])}
                </div>
            </div>
        </div>
    `;

    backdrop.classList.remove("hidden");
    drawer.classList.remove("translate-x-full");

    setTimeout(() => {
        backdrop.classList.remove("opacity-0");
        backdrop.classList.add("opacity-100");
    }, 10);
}

function closeDrawer() {
    const drawer = document.getElementById("details-drawer");
    const backdrop = document.getElementById("drawer-backdrop");

    backdrop.classList.remove("opacity-100");
    backdrop.classList.add("opacity-0");
    drawer.classList.add("translate-x-full");

    setTimeout(() => {
        backdrop.classList.add("hidden");
    }, 300);
}

// Main orchestrator to update all sections
function updateDashboard() {
    const filteredSubs = getFilteredSubsystems();

    // Update stats
    updateKPIs(filteredSubs);

    // Update statistics text
    document.getElementById("table-stats").textContent = `Showing ${filteredSubs.length} of ${PROJECT_DATA[currentProject][currentVersion].subsystems.length} subsystems`;

    // Render active tab contents
    updateTabSpecifics();
}

// Boot
window.addEventListener("DOMContentLoaded", () => {
    initSelectors();
    switchTab("scurve-tab"); // Default view
});

