                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Walkdown 1'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Walkdown 2</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Walkdown 2'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Construction Release (CRP)</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['CRP'])}</span>
