                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Precom Start</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Precom Start'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Walkdown 3</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Walkdown 3'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Precom Finish</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Precom Finish'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Definitive Energization</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Definitive Energization'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Walkdown 4</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Walkdown 4'])}</span>
                            </div>
                        </div>
                    </div>

                    <div class="border-t border-slate-200 dark:border-white/10 pt-4 flex flex-col items-center">
                        <span class="text-[10px] uppercase font-bold text-slate-500 block text-center mb-1">Turnover Package Date (TOP)</span>
                        <div class="bg-brand-500/10 text-brand-500 border border-brand-500/25 px-4 py-2.5 rounded-2xl text-center font-bold font-outfit text-base">
