            body.innerHTML = "";

            if (filteredSubs.length === 0) {
                body.innerHTML = '<tr><td colspan="100%" class="px-4 py-6 text-center text-slate-500">No subsystems found matching filters.</td></tr>';
                return;
            }

            // Generate list of weeks from all milestones in filtered dataset
            const allDates = [];
            filteredSubs.forEach(s => {
                Object.values(s.dates).forEach(d => {
                    if (d) allDates.push(new Date(d));
                });
            });

            if (allDates.length === 0) {
                body.innerHTML = '<tr><td colspan="100%" class="px-4 py-6 text-center text-slate-500">No milestone dates available.</td></tr>';
                return;
            }

            // Find min/max date
            const minDate = new Date(Math.min(...allDates));
            const maxDate = new Date(Math.max(...allDates));

            // Align to start and end of week (Sunday)
            const getEndOfWeek = (date) => {
                const day = date.getDay();
                const diff = date.getDate() - day + 6; // Sunday
                return new Date(date.setDate(diff));
            };

            let currentW = getEndOfWeek(new Date(minDate.getTime()));
            const endW = getEndOfWeek(new Date(maxDate.getTime()));
            const timelineWeeks = [];

            while (currentW <= endW) {
                timelineWeeks.push(new Date(currentW));
                currentW.setDate(currentW.getDate() + 7);
            }

            // Print columns headers
            timelineWeeks.forEach(w => {
                const wStr = w.toLocaleDateString("en-GB", { day: "2-digit", month: "short" });
                headerRow.innerHTML += `<th class="px-2 py-3 bg-slate-100 dark:bg-slate-950 text-center font-semibold min-w-[65px] border-l border-slate-200 dark:border-white/5">${wStr}</th>`;
            });

            // Map a date string to a timeline week index
            const mapDateToWeekIdx = (dStr) => {
                if (!dStr) return -1;
                const d = new Date(dStr + "T00:00:00");
                const endOfWeekD = getEndOfWeek(new Date(d.getTime()));

                for (let i = 0; i < timelineWeeks.length; i++) {
                    if (endOfWeekD.getTime() === timelineWeeks[i].getTime()) {
                        return i;
                    }
                }
                return -1;
            };

            // Render subsystem rows
            filteredSubs.sort((a,b) => a.code.localeCompare(b.code)).forEach(sub => {
                const row = document.createElement("tr");
                row.className = "hover:bg-slate-50 dark:hover:bg-white/5 border-b border-slate-200 dark:border-white/5 transition-colors cursor-pointer";
                row.onclick = () => openDrawer(sub);

                let rowHtml = `
                    <td class="px-4 py-3 sticky left-0 bg-white dark:bg-slate-900 font-medium font-outfit border-r border-slate-200 dark:border-white/5 shadow-sm">
                        <div class="font-bold text-slate-900 dark:text-white">${sub.code}</div>
                        <div class="text-[10px] text-slate-500 dark:text-slate-400 truncate max-w-[190px]">${sub.description}</div>
                    </td>
                `;

                // Build a timeline map for this subsystem
                const milestoneMap = {}; // weekIdx -> Array of milestones
                const milestoneTypes = [
                    { key: "Caminata 1", tag: "C1", cls: "color-c1" },
                    { key: "Caminata 2", tag: "C2", cls: "color-c2" },
                    { key: "Entrega Const.", tag: "CR", cls: "color-crp" },
                    { key: "Caminata 3", tag: "C3", cls: "color-c3" },
                    { key: "Caminata 4", tag: "C4", cls: "color-c4" },
                    { key: "TOP", tag: "TP", cls: "color-top" }
                ];

                milestoneTypes.forEach(mType => {
                    const dStr = sub.dates[mType.key];
                    const wIdx = mapDateToWeekIdx(dStr);
                    if (wIdx !== -1) {
                        if (!milestoneMap[wIdx]) milestoneMap[wIdx] = [];
                        milestoneMap[wIdx].push(mType);
                    }
                });

                // Generate matrix cells
                for (let i = 0; i < timelineWeeks.length; i++) {
                    const mList = milestoneMap[i] || [];
                    let cellContent = "";

                    if (mList.length > 0) {
                        // Draw milestone markers
                        mList.forEach(m => {
                            cellContent += `
                                <span class="milestone-marker ${m.cls} mx-0.5" title="${m.key}: ${formatDate(sub.dates[m.key])}">
                                    <span>${m.tag}</span>
                                </span>
                            `;
                        });
                    }

                    rowHtml += `<td class="px-2 py-3 text-center border-l border-slate-200 dark:border-white/5 min-w-[65px]">${cellContent}</td>`;
                }

                row.innerHTML = rowHtml;
                body.appendChild(row);
            });
        }

        // Render Master list table
        function renderSubsystemsTable() {
            if (activeTab !== "list-tab") return;

            const filteredSubs = getFilteredSubsystems();
            const tbody = document.getElementById("list-tbody");
            tbody.innerHTML = "";

            if (filteredSubs.length === 0) {
                tbody.innerHTML = '<tr><td colspan="12" class="px-4 py-8 text-center text-slate-500">No subsystems found matching filters.</td></tr>';
                return;
            }

            filteredSubs.sort((a,b) => a.code.localeCompare(b.code)).forEach(sub => {
                const tr = document.createElement("tr");
                tr.className = "hover:bg-slate-50 dark:hover:bg-white/5 border-b border-slate-200 dark:border-white/5 transition-colors cursor-pointer";
                tr.onclick = () => openDrawer(sub);

                tr.innerHTML = `
                    <td class="px-4 py-3 font-semibold font-outfit text-slate-900 dark:text-white sticky left-0 bg-white dark:bg-slate-900 shadow-sm">${sub.code}</td>
                    <td class="px-4 py-3 text-slate-500 dark:text-slate-400 truncate max-w-[200px]" title="${sub.description}">${sub.description}</td>
                    <td class="px-4 py-3">
                        <span class="px-2 py-0.5 rounded-full text-[10px] font-semibold bg-brand-500/10 text-brand-500 border border-brand-500/20">${sub.etapa}</span>
                    </td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Caminata 1'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Caminata 2'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Entrega Const.'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Inicio Precom'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Caminata 3'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Termino Precom'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Ener. Gen.'])}</td>
                    <td class="px-4 py-3 font-medium text-slate-600 dark:text-slate-300">${formatDate(sub.dates['Caminata 4'])}</td>
                    <td class="px-4 py-3 font-semibold text-slate-900 dark:text-white">${formatDate(sub.dates['TOP'])}</td>
                `;

                tbody.appendChild(tr);
            });
        }

        // Open details side drawer
        function openDrawer(sub) {
            const drawer = document.getElementById("details-drawer");
            const backdrop = document.getElementById("drawer-backdrop");

            const listFlags = [];
            if (sub.flags.energizacion_definitiva) listFlags.push("Definitive Energization");
            if (sub.flags.domos) listFlags.push("Domes");
            if (sub.flags.espesadores) listFlags.push("Thickeners");
            if (sub.flags.llenado_piscinas) listFlags.push("Pool Filling");
            if (sub.flags.water_run_1) listFlags.push("Water Run 1");
            if (sub.flags.water_run_2) listFlags.push("Water Run 2");

            drawer.innerHTML = `
                <div class="flex items-center justify-between border-b border-slate-200 dark:border-white/10 pb-4">
                    <div>
                        <span class="text-[10px] uppercase font-bold text-slate-500 dark:text-slate-400">Subsystem Details</span>
                        <h3 class="font-outfit font-bold text-xl text-slate-900 dark:text-white mt-0.5">${sub.code}</h3>
                    </div>
                    <button onclick="closeDrawer()" class="text-slate-500 hover:text-slate-900 dark:hover:text-white p-2 rounded-lg transition-all">
                        <i class="fa-solid fa-xmark text-lg"></i>
                    </button>
                </div>

                <div class="flex-1 overflow-y-auto space-y-5 text-sm">
                    <div>
                        <span class="text-xs text-slate-500 dark:text-slate-400 block mb-1">Description</span>
                        <p class="font-medium text-slate-800 dark:text-slate-200">${sub.description}</p>
                    </div>

                    <div>
                        <span class="text-xs text-slate-500 dark:text-slate-400 block mb-2">Stage</span>
                        <span class="px-3 py-1 rounded-full text-xs font-semibold bg-brand-500/10 text-brand-500 border border-brand-500/20">${sub.etapa}</span>
                    </div>

                    <div>
                        <span class="text-xs text-slate-500 dark:text-slate-400 block mb-2">Milestone Attributes / Tags</span>
                        <div class="flex flex-wrap gap-1.5">
                            ${listFlags.length > 0 
                                ? listFlags.map(f => `<span class="bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 text-xs px-2.5 py-1 rounded-lg border border-slate-200 dark:border-white/5">${f}</span>`).join('') 
                                : '<span class="text-slate-500 text-xs italic">No attributes tagged</span>'}
                        </div>
                    </div>

                    <div class="border-t border-slate-200 dark:border-white/10 pt-4">
                        <h4 class="font-outfit font-bold text-slate-900 dark:text-white mb-3">Milestone Schedules</h4>
                        <div class="grid grid-cols-2 gap-4">
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Caminata 1</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Caminata 1'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Caminata 2</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Caminata 2'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Entrega Const. (CRP)</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Entrega Const.'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Inicio Precom</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Inicio Precom'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Caminata 3</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Caminata 3'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Termino Precom</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Termino Precom'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Energización Definitiva</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Ener. Gen.'])}</span>
                            </div>
                            <div>
                                <span class="text-[10px] uppercase font-bold text-slate-500 block">Caminata 4</span>
                                <span class="font-medium text-slate-800 dark:text-slate-200 text-xs">${formatDate(sub.dates['Caminata 4'])}</span>
                            </div>
                        </div>
                    </div>

                    <div class="border-t border-slate-200 dark:border-white/10 pt-4 flex flex-col items-center">
                        <span class="text-[10px] uppercase font-bold text-slate-500 block text-center mb-1">Turnover Package Date (TOP)</span>
                        <div class="bg-brand-500/10 text-brand-500 border border-brand-500/25 px-4 py-2.5 rounded-2xl text-center font-bold font-outfit text-base">
                            ${formatDate(sub.dates['TOP'])}
                        </div>
                    </div>
                </div>
            `;

            backdrop.classList.remove("hidden");
            drawer.classList.remove("translate-x-full");

            setTimeout(() => {
                backdrop.classList.remove("opacity-0");
                backdrop.classList.add("opacity-100");
            }, 10);
        }

        function closeDrawer() {
            const drawer = document.getElementById("details-drawer");
            const backdrop = document.getElementById("drawer-backdrop");

            backdrop.classList.remove("opacity-100");
            backdrop.classList.add("opacity-0");
            drawer.classList.add("translate-x-full");

            setTimeout(() => {
                backdrop.classList.add("hidden");
            }, 300);
        }

        // Export active filtered table to CSV
        function exportToCSV() {
            const filteredSubs = getFilteredSubsystems();
            if (filteredSubs.length === 0) return;

            let csvContent = "\uFEFF"; // UTF-8 BOM
            csvContent += "Subsystem,Description,Stage,Caminata 1,Caminata 2,Entrega Const. (CRP),Inicio Precom,Caminata 3,Termino Precom,Ener. Gen.,Caminata 4,TOP\n";

            filteredSubs.forEach(s => {
                const row = [
                    s.code,
                    `"${s.description.replace(/"/g, '""')}"`,
                    s.etapa,
                    s.dates['Caminata 1'] || "",
                    s.dates['Caminata 2'] || "",
                    s.dates['Entrega Const.'] || "",
                    s.dates['Inicio Precom'] || "",
                    s.dates['Caminata 3'] || "",
                    s.dates['Termino Precom'] || "",
                    s.dates['Ener. Gen.'] || "",
                    s.dates['Caminata 4'] || "",
                    s.dates['TOP'] || ""
                ];
                csvContent += row.join(",") + "\n";
            });

            const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
            const link = document.createElement("a");
            const url = URL.createObjectURL(blob);
            link.setAttribute("href", url);
            link.setAttribute("download", `PreCom_TOP_Report_${currentProject.replace(/\s+/g, '_')}_${currentVersion.replace(/\s+/g, '_')}.csv`);
            link.style.visibility = "hidden";
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }

        // Main orchestrator to update all sections
        function updateDashboard() {
            const filteredSubs = getFilteredSubsystems();

            // Update stats
            updateKPIs(filteredSubs);

            // Update statistics text
            document.getElementById("table-stats").textContent = `Showing ${filteredSubs.length} of ${PROJECT_DATA[currentProject][currentVersion].subsystems.length} subsystems`;

            // Render active tab contents
            updateTabSpecifics();
        }

        // Boot
        window.addEventListener("DOMContentLoaded", () => {
            initSelectors();
            switchTab("scurve-tab"); // Default view
        });
    </script>
</body>
</html>

