import os
import openpyxl

workspace_dir = r"c:\Users\Pablo Villegas\OneDrive\Documents\Claude\Skylines\PreCom"

def search_in_file(filename):
    path = os.path.join(workspace_dir, filename)
    print(f"=== Searching in {path} ===")
    if not os.path.exists(path):
        print(f"File not found: {path}")
        return
    wb = openpyxl.load_workbook(path, data_only=True)
    for sheet in wb.sheetnames:
        ws = wb[sheet]
        count = 0
        for r_idx, row in enumerate(ws.iter_rows(values_only=True)):
            for c_idx, val in enumerate(row):
                if val is not None:
                    val_str = str(val).lower()
                    if "rev.b" in val_str or "rev.0" in val_str or "rev b" in val_str or "rev 0" in val_str:
                        print(f"[{sheet}] Row {r_idx}, Col {c_idx}: {val}")
                        count += 1
                        if count > 30:
                            print("Too many matches, truncating...")
                            return

search_in_file("Programa 18.07.22  Con Caminatas (ODPT Feb1) .xlsx")
search_in_file("Programa 18.07.22  Con Caminatas (ODPT Feb1)_Input.xlsx")
